"""Core definitions for the dataflow framework."""


class ServiceError(Exception):
    """Raised when a service operation fails."""

    def __init__(self, service, message, code=None, cause=None):
        self.service = service
        self.message = message
        self.code = code
        self.cause = cause
        super().__init__(f"[{service}] {message}")


def create_service(name, kind="memory", **kwargs):
    """Factory function to create a new service instance."""
    if kind == "memory":
        return {"name": name, "kind": kind, "data": {}, **kwargs}
    elif kind == "disk":
        return {"name": name, "kind": kind, "path": f"/tmp/{name}", **kwargs}
    else:
        raise ServiceError(name, f"Unknown service kind: {kind}", code=400)

