"""Data transformation operations."""

from .core import ServiceError


class Transformer:
    """Applies transformations to data records."""

    def __init__(self, name="default"):
        self.name = name
        self._transforms = []

    def add(self, func, label="unnamed"):
        """Register a transformation function."""
        self._transforms.append({"func": func, "label": label})

    def apply(self, record):
        """Apply all transforms to a record."""
        result = record
        for t in self._transforms:
            try:
                result = t["func"](result)
            except Exception as e:
                raise ServiceError(self.name, f"Transform '{t['label']}' failed: {e}", cause=e)
        return result

seed_files.dataflow/filter_mod.py:
"""Data filtering operations."""

from .core import ServiceError


class DataFilter:
    """Filters data records based on predicates."""

    def __init__(self, name="default"):
        self.name = name
        self._predicates = []

    def add_predicate(self, func, label="unnamed"):
        """Add a filter predicate."""
        self._predicates.append({"func": func, "label": label})

    def apply(self, records):
        """Apply all predicates, returning matching records."""
        result = []
        for rec in records:
            try:
                if all(p["func"](rec) for p in self._predicates):
                    result.append(rec)
            except Exception as e:
                raise ServiceError(self.name, f"Filter failed: {e}", cause=e)
        return result

