"""Batch processing of data records."""

from .core import ServiceError, create_service


class BatchProcessor:
    """Processes data in fixed-size batches."""

    def __init__(self, batch_size=100):
        self.batch_size = batch_size
        self._buffer = create_service("batch_buffer", kind="memory")
        self._processed = 0

    def submit(self, records):
        """Submit records for batch processing."""
        if not records:
            raise ServiceError("batch", "Cannot submit empty batch", code=400)
        self._processed += len(records)
        return {"accepted": len(records), "total": self._processed}

    def stats(self):
        """Return batch processing statistics."""
        return {"processed": self._processed, "batch_size": self.batch_size}

