"""Streaming data reader."""

from .core import ServiceError, create_service


class StreamReader:
    """Reads data as a continuous stream."""

    def __init__(self, name, buffer_size=1024):
        self.name = name
        self.buffer_size = buffer_size
        self._backend = create_service(f"{name}_stream", kind="memory")
        self._position = 0

    def read_next(self, count=1):
        """Read the next N records from the stream."""
        if count <= 0:
            raise ServiceError(self.name, "Count must be positive", code=400)
        self._position += count
        return {"records": [], "position": self._position}

    def reset(self):
        """Reset stream to beginning."""
        self._position = 0

seed_files.dataflow/validate.py:
"""Data validation module."""

from .core import ServiceError


class Validator:
    """Validates data records against rules."""

    def __init__(self):
        self._rules = {}

    def add_rule(self, field, rule_func, message="Validation failed"):
        """Add a validation rule for a field."""
        self._rules[field] = {"func": rule_func, "message": message}

    def check(self, record):
        """Validate a record against all rules."""
        errors = []
        for field_name, rule in self._rules.items():
            value = record.get(field_name)
            if not rule["func"](value):
                errors.append(f"{field_name}: {rule['message']}")
        if errors:
            raise ServiceError("validator", "; ".join(errors), code=422)
        return True

