"""Data serialization module."""

import json
from .core import ServiceError, create_service


class Serializer:
    """Serializes and deserializes data records."""

    def __init__(self, format="json"):
        self.format = format
        self._store = create_service("serializer_store", kind="memory")

    def encode(self, data):
        """Encode data to string."""
        try:
            if self.format == "json":
                return json.dumps(data)
            raise ServiceError("serializer", f"Unknown format: {self.format}", code=400)
        except (TypeError, ValueError) as e:
            raise ServiceError("serializer", f"Encode failed: {e}", cause=e)

    def decode(self, raw):
        """Decode string to data."""
        try:
            if self.format == "json":
                return json.loads(raw)
            raise ServiceError("serializer", f"Unknown format: {self.format}", code=400)
        except json.JSONDecodeError as e:
            raise ServiceError("serializer", f"Decode failed: {e}", cause=e)

