"""Task queue for deferred processing."""

from .core import ServiceError, create_service


class TaskQueue:
    """FIFO queue for deferred task processing."""

    def __init__(self, name="default"):
        self.name = name
        self._backend = create_service(f"{name}_queue", kind="memory")
        self._items = []

    def enqueue(self, item):
        """Add an item to the queue."""
        if item is None:
            raise ServiceError(self.name, "Cannot enqueue None", code=400)
        self._items.append(item)
        return len(self._items)

    def dequeue(self):
        """Remove and return the next item."""
        if not self._items:
            raise ServiceError(self.name, "Queue is empty", code=404)
        return self._items.pop(0)

    def size(self):
        """Return queue size."""
        return len(self._items)

