"""Task scheduling module."""

from .core import ServiceError


class Scheduler:
    """Schedules tasks for periodic execution."""

    def __init__(self):
        self._tasks = {}

    def schedule(self, name, func, interval=60):
        """Schedule a named task."""
        self._tasks[name] = {"func": func, "interval": interval, "runs": 0}

    def run_task(self, name):
        """Manually trigger a scheduled task."""
        if name not in self._tasks:
            raise ServiceError("scheduler", f"Unknown task: {name}", code=404)
        task = self._tasks[name]
        task["func"]()
        task["runs"] += 1
        return task["runs"]

    def list_tasks(self):
        """List all scheduled task names."""
        return list(self._tasks.keys())

