"""Alert management module."""

from .core import ServiceError


class AlertManager:
    """Manages alerts based on metric thresholds."""

    def __init__(self):
        self._rules = {}
        self._fired = []

    def add_rule(self, name, condition_func, message="Alert triggered"):
        """Add an alert rule."""
        self._rules[name] = {"func": condition_func, "message": message}

    def evaluate(self, context):
        """Evaluate all rules against the given context."""
        alerts = []
        for name, rule in self._rules.items():
            try:
                if rule["func"](context):
                    alerts.append({"name": name, "message": rule["message"]})
                    self._fired.append(name)
            except Exception as e:
                raise ServiceError("alert", f"Rule '{name}' failed: {e}", cause=e)
        return alerts

    def fired_count(self):
        """Return number of alerts fired."""
        return len(self._fired)

