"""Data partitioning module."""

from .core import ServiceError, create_service


class Partitioner:
    """Partitions data records by key."""

    def __init__(self, key_func=None):
        self.key_func = key_func or (lambda r: r.get("id", 0) % 4)
        self._store = create_service("partition_store", kind="memory")

    def partition(self, records):
        """Partition records into buckets."""
        if not records:
            raise ServiceError("partition", "Cannot partition empty list", code=400)
        buckets = {}
        for rec in records:
            key = self.key_func(rec)
            if key not in buckets:
                buckets[key] = []
            buckets[key].append(rec)
        return buckets

    def bucket_count(self, records):
        """Return number of distinct buckets."""
        return len(self.partition(records))

seed_files.dataflow/merge.py:
"""Data merging module."""

from .core import ServiceError, create_service


class Merger:
    """Merges multiple data streams."""

    def __init__(self, strategy="concat"):
        self.strategy = strategy
        self._store = create_service("merge_store", kind="memory")

    def merge(self, *streams):
        """Merge multiple record streams."""
        if not streams:
            raise ServiceError("merge", "At least one stream required", code=400)
        if self.strategy == "concat":
            result = []
            for s in streams:
                result.extend(s)
            return result
        raise ServiceError("merge", f"Unknown strategy: {self.strategy}", code=400)

    def merge_count(self, *streams):
        """Return total record count across streams."""
        return sum(len(s) for s in streams)

