"""Pipeline orchestration module."""

from .core import ServiceError, create_service


class Pipeline:
    """Orchestrates a sequence of data processing steps."""

    def __init__(self, name="default"):
        self.name = name
        self._steps = []
        self._store = create_service(f"{name}_pipeline", kind="memory")

    def add_step(self, func, label="step"):
        """Add a processing step to the pipeline."""
        self._steps.append({"func": func, "label": label})

    def run(self, data):
        """Execute all pipeline steps in order."""
        result = data
        for step in self._steps:
            try:
                result = step["func"](result)
            except ServiceError:
                raise
            except Exception as e:
                raise ServiceError(self.name, f"Step '{step['label']}' failed: {e}", cause=e)
        return result

    def step_count(self):
        """Return number of steps."""
        return len(self._steps)

